 1	import * as React from 'react';
 2	import { Icon, Split, SplitItem } from '@patternfly/react-core';
 3	import { ExclamationTriangleIcon } from '@patternfly/react-icons/dist/esm/icons/exclamation-triangle-icon';
 4	import { t_global_color_status_warning_default as warningColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_warning_default';
 5	import { Trans, useTranslation } from 'react-i18next';
 6	import { PipelineKind } from '../../types';
 7	import TriggerTemplateSelector from './TriggerTemplateSelector';
 8	
 9	type RemoveTriggerFormProps = {
10	  pipeline: PipelineKind;
11	};
12	
13	const RemoveTriggerForm: React.FC<RemoveTriggerFormProps> = (props) => {
14	  const { t } = useTranslation('plugin__pipelines-console-plugin');
15	  const { pipeline } = props;
16	  const pipelineName = pipeline.metadata.name;
17	
18	  return (
19	    <Split className="odc-modal-content" hasGutter>
20	      <SplitItem>
21	        <Icon size="md">
22	          <ExclamationTriangleIcon color={warningColor.value} />
23	        </Icon>
24	      </SplitItem>
25	      <SplitItem isFilled>
26	        <p className="co-break-word">
27	          <Trans t={t}>
28	            Select the trigger to remove from pipeline <b>{{ pipelineName }}</b>
29	            .
30	          </Trans>
31	        </p>
32	        <TriggerTemplateSelector
33	          name="selectedTrigger"
34	          placeholder={t('Select TriggerTemplate')}
35	          pipeline={pipeline}
36	        />
37	      </SplitItem>
38	    </Split>
39	  );
40	};
41	
42	export default RemoveTriggerForm;

